function addLiquidity(
    address tokenA,
    address tokenB,
    uint amountADesired,
    uint amountBDesired,
    uint amountAMin,
    uint amountBMin,
    address to,
    uint deadline
) external virtual override ensure(deadline) returns (uint amountA, uint amountB, uint liquidity) {
    (amountA, amountB) = _addLiquidity(tokenA, tokenB, amountADesired, amountBDesired, amountAMin, amountBMin);
    address pair = PancakeLibrary.pairFor(factory, tokenA, tokenB);
    TransferHelper.safeTransferFrom(tokenA, msg.sender, pair, amountA);
    TransferHelper.safeTransferFrom(tokenB, msg.sender, pair, amountB);
    liquidity = IPancakePair(pair).mint(to);
}

function removeLiquidityETHWithPermit(
    address token,
    uint liquidity,
    uint amountTokenMin,
    uint amountETHMin,
    address to,
    uint deadline,
    bool approveMax, uint8 v, bytes32 r, bytes32 s
) external virtual override returns (uint amountToken, uint amountETH) {
    address pair = PancakeLibrary.pairFor(factory, token, WETH);
    uint value = approveMax ? uint(-1) : liquidity;
    IPancakePair(pair).permit(msg.sender, address(this), value, deadline, v, r, s);
    (amountToken, amountETH) = removeLiquidityETH(token, liquidity, amountTokenMin, amountETHMin, to, deadline);
}

function removeLiquidityETHSupportingFeeOnTransferTokens(
    address token,
    uint liquidity,
    uint amountTokenMin,
    uint amountETHMin,
    address to,
    uint deadline
) public virtual override ensure(deadline) returns (uint amountETH) {
    (, amountETH) = removeLiquidity(
        token,
        WETH,
        liquidity,
        amountTokenMin,
        amountETHMin,
        address(this),
        deadline
    );
    TransferHelper.safeTransfer(token, to, IERC20(token).balanceOf(address(this)));
    IWETH(WETH).withdraw(amountETH);
    TransferHelper.safeTransferETH(to, amountETH);
}

function removeLiquidityETHWithPermitSupportingFeeOnTransferTokens(
    address token,
    uint liquidity,
    uint amountTokenMin,
    uint amountETHMin,
    address to,
    uint deadline,
    bool approveMax, uint8 v, bytes32 r, bytes32 s
) external virtual override returns (uint amountETH) {
    address pair = PancakeLibrary.pairFor(factory, token, WETH);
    uint value = approveMax ? uint(-1) : liquidity;
    IPancakePair(pair).permit(msg.sender, address(this), value, deadline, v, r, s);
    amountETH = removeLiquidityETHSupportingFeeOnTransferTokens(
        token, liquidity, amountTokenMin, amountETHMin, to, deadline
    );
}

function proposeUpgrade(
    address proxyAddress,
    string memory newImplementationContractName,
    Options memory opts
) internal returns (ProposeUpgradeResponse memory) {
    opts.defender.useDefenderDeploy = true;
    address proxyAdminAddress = Core.getAdminAddress(proxyAddress);
    address newImplementationAddress = Core.prepareUpgrade(newImplementationContractName, opts);
    return
        DefenderDeploy.proposeUpgrade(
            proxyAddress,
            proxyAdminAddress,
            newImplementationAddress,
            newImplementationContractName,
            opts
        );
}

function isOperatorAllowed(address registrant, address operator) external view returns (bool) {
    address registration = _registrations[registrant];
    if (registration != address(0)) {
        EnumerableSet.AddressSet storage filteredOperatorsRef;
        EnumerableSet.Bytes32Set storage filteredCodeHashesRef;

        filteredOperatorsRef = _filteredOperators[registration];
        filteredCodeHashesRef = _filteredCodeHashes[registration];

        if (filteredOperatorsRef.contains(operator)) {
            revert AddressFiltered(operator);
        }
        if (operator.code.length > 0) {
            bytes32 codeHash = operator.codehash;
            if (filteredCodeHashesRef.contains(codeHash)) {
                revert CodeHashFiltered(operator, codeHash);
            }
        }
    }
    return true;
}

function calculateMinAmount(
  uint256 midPriceNumerator,
  uint256 midPriceDenominator,
  uint256 amount,
  uint256 maxSlippage // as fraction
) public pure returns (uint256) {
  FixidityLib.Fraction memory maxSlippageFraction = FixidityLib.wrap(maxSlippage);

  FixidityLib.Fraction memory price = FixidityLib.newFixedFraction(
    midPriceNumerator,
    midPriceDenominator
  );
  FixidityLib.Fraction memory amountFraction = FixidityLib.newFixed(amount);
  FixidityLib.Fraction memory totalAmount = price.multiply(amountFraction);

  return
    totalAmount
      .subtract(price.multiply(maxSlippageFraction).multiply(amountFraction))
      .fromFixed();
}

function transferFrom(address from, address to, uint256 value) external returns (bool) {
  require(to != address(0), "transfer attempted to reserved address 0x0");
  require(value <= balanceOf(from), "transfer value exceeded balance of sender");
  require(
    value <= allowed[from][msg.sender],
    "transfer value exceeded sender's allowance for spender"
  );

  bool success;
  (success, ) = TRANSFER.call.value(0).gas(gasleft())(abi.encode(from, to, value));
  require(success, "CELO transfer failed");

  allowed[from][msg.sender] = allowed[from][msg.sender].sub(value);
  emit Transfer(from, to, value);
  return true;
}

function modexp(
    bytes memory base,
    bytes memory exponent,
    bytes memory modulus
) internal view returns (bool success, bytes memory output) {
    bytes memory input = abi.encodePacked(
        uint256(base.length),
        uint256(exponent.length),
        uint256(modulus.length),
        base,
        exponent,
        modulus
    );

    output = new bytes(modulus.length);

    assembly {
        success := staticcall(
            gas(),
            5,
            add(input, 32),
            mload(input),
            add(output, 32),
            mload(modulus)
        )
    }
}

function _validateAdditionalParametersAndGetOfferedItemId(
    address collection,
    bytes calldata makerAdditionalParameters,
    bytes calldata takerAdditionalParameters
) private view returns (uint256) {
    (
        bytes32 messageId,
        bytes memory payload,
        uint256 timestamp,
        bytes memory signature,
        uint256 offeredItemId
    ) = abi.decode(takerAdditionalParameters, (bytes32, bytes, uint256, bytes, uint256));

    uint256 transferCooldownPeriod = abi.decode(makerAdditionalParameters, (uint256));

    _verifyReservoirOracle(
        collection,
        offeredItemId,
        transferCooldownPeriod,
        messageId,
        payload,
        timestamp,
        signature
    );

    return offeredItemId;
}

function transferAllowed(
    address mToken,
    address src,
    address dst,
    uint transferTokens
) external override returns (uint) {
    // Pausing is a very serious situation - we revert to sound the alarms
    require(!transferGuardianPaused, "transfer is paused");

    // Currently the only consideration is whether or not
    //  the src is allowed to redeem this many tokens
    uint allowed = redeemAllowedInternal(mToken, src, transferTokens);
    if (allowed != uint(Error.NO_ERROR)) {
        return allowed;
    }

    // Keep the flywheel moving
    updateAndDistributeSupplierRewardsForToken(mToken, src);
    updateAndDistributeSupplierRewardsForToken(mToken, dst);

    return uint(Error.NO_ERROR);
}

function setAllowedToVoteOverMaxNumberOfGroups(bool flag) public {
  address account = getAccounts().voteSignerToAccount(msg.sender);
  IValidators validators = getValidators();
  require(
    !validators.isValidator(account),
    "Validators cannot vote for more than max number of groups"
  );
  require(
    !validators.isValidatorGroup(account),
    "Validator groups cannot vote for more than max number of groups"
  );

  if (!flag) {
    require(
      votes.groupsVotedFor[account].length <= maxNumGroupsVotedFor,
      "Too many groups voted for!"
    );
  }

  allowedToVoteOverMaxNumberOfGroups[account] = flag;
  emit AllowedToVoteOverMaxNumberOfGroups(account, flag);
}

function updateParticipationBaseline(Proposals.Proposal storage proposal) private {
  FixidityLib.Fraction memory participation = proposal.getParticipation();
  FixidityLib.Fraction memory participationComponent = participation.multiply(
    participationParameters.baselineUpdateFactor
  );
  FixidityLib.Fraction memory baselineComponent = participationParameters.baseline.multiply(
    FixidityLib.fixed1().subtract(participationParameters.baselineUpdateFactor)
  );
  participationParameters.baseline = participationComponent.add(baselineComponent);
  if (participationParameters.baseline.lt(participationParameters.baselineFloor)) {
    participationParameters.baseline = participationParameters.baselineFloor;
  }
  emit ParticipationBaselineUpdated(participationParameters.baseline.unwrap());
}

function deletePayment(address paymentId) private {
  EscrowedPayment storage payment = escrowedPayments[paymentId];
  address[] storage received = receivedPaymentIds[payment.recipientIdentifier];
  address[] storage sent = sentPaymentIds[payment.sender];

  escrowedPayments[received[received.length - 1]].receivedIndex = payment.receivedIndex;
  received[payment.receivedIndex] = received[received.length - 1];
  received.length = received.length.sub(1);

  escrowedPayments[sent[sent.length - 1]].sentIndex = payment.sentIndex;
  sent[payment.sentIndex] = sent[sent.length - 1];
  sent.length = sent.length.sub(1);

  delete escrowedPayments[paymentId];
  delete trustedIssuersPerPayment[paymentId];
  emit TrustedIssuersUnset(paymentId);
}

function executeTransaction(uint transactionId)
    public
    ownerExists(msg.sender)
    confirmed(transactionId, msg.sender)
    notExecuted(transactionId)
    {
        if (isConfirmed(transactionId)) {
            Transaction storage txn = transactions[transactionId];
            txn.executed = true;
            if (external_call(txn.destination, txn.value, txn.data.length, txn.data)) {
                emit Execution(transactionId);
            } else {
                emit ExecutionFailure(transactionId);
                txn.executed = false;
            }
        }
    }

function _debitMsgSender(uint _amount) internal returns (uint messageFee) {
    uint msgSenderBalance = balanceOf(msg.sender);

    if (msgSenderBalance < _amount) {
        require(msgSenderBalance + msg.value >= _amount, "NativeOFTV2: Insufficient msg.value");

        // user can cover difference with additional msg.value ie. wrapping
        uint mintAmount = _amount - msgSenderBalance;
        _mint(address(msg.sender), mintAmount);

        // update the messageFee to take out mintAmount
        messageFee = msg.value - mintAmount;
    } else {
        messageFee = msg.value;
    }

    _transfer(msg.sender, address(this), _amount);
    return messageFee;
}

function getEther(
    ERC20 src,
    address destAddress,
    uint maxDestAmount,
    uint minConversionRate,
    address walletId
)
    public
{
    // Use the full balance of tokens transferred from the trade executor
    uint256 srcAmount = src.balanceOf(this);

    if (src.allowance(this, exchange) < srcAmount) {
        // Approve the exchange to transfer tokens from this contract to the reserve
        src.approve(exchange, MAX_UINT);
    }

    Kyber(exchange).trade(
        src,
        srcAmount,
        ETH_TOKEN_ADDRESS,
        destAddress,
        maxDestAmount,
        minConversionRate,
        walletId
    );
}

function beforeHook(
    bytes calldata _terms,
    bytes calldata,
    ModeCode _mode,
    bytes calldata,
    bytes32,
    address,
    address
)
    public
    view
    override
    onlyDefaultExecutionMode(_mode)
{
    (uint128 blockAfterThreshold_, uint128 blockBeforeThreshold_) = getTermsInfo(_terms);

    if (blockAfterThreshold_ > 0) {
        // this means there has been a after blocknumber set for which the delegation must be used
        require(block.number > blockAfterThreshold_, "BlockNumberEnforcer:early-delegation");
    }

    if (blockBeforeThreshold_ > 0) {
        // this means there has been a before blocknumber set for which the delegation must be used
        require(block.number < blockBeforeThreshold_, "BlockNumberEnforcer:expired-delegation");
    }
}

function beforeHook(
    bytes calldata _terms,
    bytes calldata,
    ModeCode _mode,
    bytes calldata,
    bytes32,
    address,
    address
)
    public
    view
    override
    onlyDefaultExecutionMode(_mode)
{
    (uint128 timestampAfterThreshold_, uint128 timestampBeforeThreshold_) = getTermsInfo(_terms);

    if (timestampAfterThreshold_ > 0) {
        // this means there has been a timestamp set for after which the delegation can be used
        require(block.timestamp > timestampAfterThreshold_, "TimestampEnforcer:early-delegation");
    }

    if (timestampBeforeThreshold_ > 0) {
        // this means there has been a timestamp set for before which the delegation can be used
        require(block.timestamp < timestampBeforeThreshold_, "TimestampEnforcer:expired-delegation");
    }
}

function buyNFT(ListingData calldata listingData, address paymentCurrency)
    override
    external
    checkListingData(listingData, paymentCurrency) {

        // Check balances and allowances, convert payment currency if needed, calculate royalties and transfer funds
        checkAndTransferFunds(listingData, paymentCurrency);

        // Transfer NFT to new Owner
        IERC721(contractRegistry.getContractAddress(ACCOUNT_TOKEN_HASH)).safeTransferFrom(
            listingData.tokenOwner,
            msg.sender,
            listingData.tokenId
        );

        emit NFTSold(listingData.tokenId, paymentCurrency, listingData.amount);

    }

function buyNFT(ListingData calldata listingData, address paymentCurrency, uint256 amountInMax, uint256 treasuryRoyaltiesMin)
    override
    external
    checkListingData(listingData, paymentCurrency) {

        // Check balances and allowances, convert payment currency if needed, calculate royalties and transfer funds
        checkAndTransferFunds(listingData, paymentCurrency, amountInMax, treasuryRoyaltiesMin);

        // Prevent replay attacks and reentrancy
        invalidatedListingHashes[getListingDataHash(listingData)] = true;

        // Transfer NFT to new Owner
        IERC721(contractRegistry.getContractAddress(ACCOUNT_TOKEN_HASH)).safeTransferFrom(
            listingData.tokenOwner,
            msg.sender,
            listingData.tokenId
        );

        emit NFTSold(listingData.tokenId, paymentCurrency, listingData.amount);

    }

function revokeListing(ListingData calldata listingData) override external {

    bytes32 listingHash = getListingDataHash(listingData);
    require(!invalidatedListingHashes[listingHash], "Listing already revoked");

    address seller = ECDSA.recover(listingHash, listingData.signature);
    require(seller == listingData.tokenOwner, "Bad listing request");

    require(msg.sender == seller, "Only the seller can revoke his listing");

    invalidatedListingHashes[listingHash] = true;

    emit NFTListingRevoked(listingData.tokenId, listingHash);
}

function liquidateAccount(uint256 nftId) public verifySenderAndNFT(nftId) override {

    rebaseStaking();

    IAccountToken accountTokens = IAccountToken(contractRegistry.getContractAddress(ACCOUNT_TOKEN_HASH));

    bool liquidated = accountTokens.requestLiquidation(nftId);
    if (liquidated) {

        IRewardDistributor rewardDistributor = IRewardDistributor(contractRegistry.getContractAddress(REWARD_DISTRIBUTOR_HASH));
        IStakingManager stakingManager = IStakingManager(contractRegistry.getContractAddress(STAKING_MANAGER_HASH));

        rewardDistributor.liquidateAccount(nftId);
        stakingManager.liquidateAccount(nftId, msg.sender);

        emit AccountLiquidated(nftId);
    } else {
        emit AccountLiquidationStarted(nftId);
    }
}

function _setLiquidationIncentive(
    uint newLiquidationIncentiveMantissa
) external returns (uint) {
    // Check caller is admin
    if (msg.sender != admin) {
        return
            fail(
                Error.UNAUTHORIZED,
                FailureInfo.SET_LIQUIDATION_INCENTIVE_OWNER_CHECK
            );
    }

    // Save current value for use in log
    uint oldLiquidationIncentiveMantissa = liquidationIncentiveMantissa;

    // Set liquidation incentive to new incentive
    liquidationIncentiveMantissa = newLiquidationIncentiveMantissa;

    // Emit event with old incentive, new incentive
    emit NewLiquidationIncentive(
        oldLiquidationIncentiveMantissa,
        newLiquidationIncentiveMantissa
    );

    return uint(Error.NO_ERROR);
}

function debit(
    address rateLimitedAllowance,
    address tokenAddress,
    address userAddress,
    uint256 amount
) external whenNotPaused onlyRole(EXECUTIONER_ROLE) {
    require(
        rateLimitedAllowance != address(0),
        "Invalid rate limited contract"
    );
    require(tokenAddress != address(0), "Invalid token address");
    require(userAddress != address(0), "Invalid user address");

    IRateLimitedAllowance(rateLimitedAllowance).transferFrom(
        userAddress,
        beneficiary,
        amount,
        tokenAddress
    );

    emit Withdraw(
        tokenAddress,
        userAddress,
        beneficiary,
        rateLimitedAllowance,
        amount
    );
}

function rebroadcastProposal(uint256 proposalId) external payable {
    ProposalState proposalState = state(proposalId);
    require(
        proposalState == ProposalState.Active,
        "MultichainGovernor: invalid state"
    );

    Proposal storage proposal = proposals[proposalId];

    bytes memory payload = abi.encode(
        proposalId,
        proposal.voteSnapshotTimestamp,
        proposal.votingStartTime,
        proposal.votingEndTime,
        proposal.crossChainVoteCollectionEndTimestamp
    );

    _bridgeOutAll(payload);

    emit ProposalRebroadcasted(proposalId, payload);
}

function rebroadcastProposal(uint256 proposalId) external payable {
    ProposalState proposalState = state(proposalId);
    if (proposalState != ProposalState.Active) {
        revert InvalidProposalState(proposalState, ProposalState.Active);
    }

    Proposal storage proposal = proposals[proposalId];

    bytes memory payload = abi.encode(
        proposalId,
        proposal.voteSnapshotTimestamp,
        proposal.votingStartTime,
        proposal.votingEndTime,
        proposal.crossChainVoteCollectionEndTimestamp
    );

    _bridgeOutAll(payload);

    emit ProposalRebroadcasted(proposalId, payload);
}

function getBorrowRate(
    uint cash,
    uint borrows,
    uint reserves
) public view override returns (uint) {
    uint util = utilizationRate(cash, borrows, reserves);

    if (util <= kink) {
        return
            util.mul(multiplierPerTimestamp).div(1e18).add(
                baseRatePerTimestamp
            );
    } else {
        uint normalRate = kink.mul(multiplierPerTimestamp).div(1e18).add(
            baseRatePerTimestamp
        );
        uint excessUtil = util.sub(kink);
        return
            excessUtil.mul(jumpMultiplierPerTimestamp).div(1e18).add(
                normalRate
            );
    }
}

function initialize(
    address underlying_,
    ComptrollerInterface comptroller_,
    InterestRateModel interestRateModel_,
    uint initialExchangeRateMantissa_,
    string memory name_,
    string memory symbol_,
    uint8 decimals_
) public {
    // MToken initialize does the bulk of the work
    super.initialize(
        comptroller_,
        interestRateModel_,
        initialExchangeRateMantissa_,
        name_,
        symbol_,
        decimals_
    );

    // Set underlying and sanity check it
    underlying = underlying_;
    EIP20Interface(underlying).totalSupply();
}

function _setPendingImplementation(
    address newPendingImplementation
) public returns (uint) {
    if (msg.sender != admin) {
        return
            fail(
                Error.UNAUTHORIZED,
                FailureInfo.SET_PENDING_IMPLEMENTATION_OWNER_CHECK
            );
    }

    address oldPendingImplementation = pendingComptrollerImplementation;

    pendingComptrollerImplementation = newPendingImplementation;

    emit NewPendingImplementation(
        oldPendingImplementation,
        pendingComptrollerImplementation
    );

    return uint(Error.NO_ERROR);
}
